from itertools import islice
from heapq import heappop, heappush
from sympy import nextprime
def A145108_gen(): # generator of terms if the first n terms are desired.
    h, hset = [(4,{2:2})], {4}
    while True:
        m, ps = heappop(h)
        yield m
        pf = sorted(ps.keys())
        l = len(pf)
